parent_id = #{parentId}, menu_name = #{menuName}, menu_type = #{menuType}, permission = #{permission}, path = #{path}, component = #{component}, icon = #{icon}, sort_order = #{sortOrder}, visible = #{visible}, status = #{status}, del_flag = #{delFlag}, update_by = #{updateBy}, remark = #{remark},
